-- Alex_C.T modular Profilarr v4 PCD operations.
-- 05: Audio codec, channel-layout, and lossless-audio definitions.
-- Requires 01.

INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: Surround Bonus', '(?i)\b(?:5[ ._-]?1|6[ ._-]?1|7[ ._-]?1|6ch|7ch|8ch|5\.1ch|6\.1ch|7\.1ch|dolby[ ._-]?atmos|ddp[ ._-]?atmos|ec3[ ._-]?joc|atmos|dts(?:[ ._-]?hd)?(?:[ ._-]?ma)?|truehd|true[ ._-]?hd)\b', 'Standalone surround-audio signal for movie scoring. Matches explicit 5.1+ channel layouts plus Atmos, DTS-HD, and TrueHD style markers without bundling the score together with HDR or codec rules.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Surround Bonus', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Surround Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: 5.1 Surround Preferred', '(?i)\b(?:5[ ._-]?1|6ch|5\.1ch)\b', 'Primary surround-audio bonus for 5.1, 6-channel, and 5.1ch tags. This is the main compatibility target for a shared media-server setup built around a 5.1-capable soundbar.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 5.1 Surround Preferred', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 5.1 Surround Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: Atmos Bonus', '(?i)\b(?:dolby[ ._-]?atmos|ddp[ ._-]?atmos|ec3[ ._-]?joc|atmos)\b', 'Top audio bonus for Dolby Atmos, DDP Atmos, EC3 JOC, and Atmos tags. Atmos is preferred when available because it still rides on a practical Dolby Digital Plus playback path.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Atmos Bonus', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Atmos Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: EAC3-AC3 Preferred', '(?i)\b(?:eac3|e-ac-3|ddp|dd\+|ac3|ac-3|dolby[ ._-]?digital[ ._-]?plus|dolby[ ._-]?digital)\b', 'Preferred Dolby audio-format bonus for EAC3, DDP, DD+, AC3, and Dolby Digital tags. These formats stay highly compatible for shared media-server, eARC, and streaming-style playback.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: EAC3-AC3 Preferred', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: EAC3-AC3 Preferred', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: 6.1 Bonus', '(?i)\b(?:6[ ._-]?1|7ch|6\.1ch)\b', 'Secondary channel-layout bonus for 6.1 audio. It stays below the main 5.1 and Dolby-format preferences, but above 7.1 and stereo in the fallback ladder.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 6.1 Bonus', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 6.1 Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: 7.1 Bonus', '(?i)\b(?:7[ ._-]?1|8ch|7\.1ch)\b', 'Smaller channel-layout bonus for 7.1 audio. It remains below the 5.1-first compatibility target and below 6.1 in the current managed fallback order.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 7.1 Bonus', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: 7.1 Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: AAC Fallback Marker', '(?i)\baac\b', 'Lowest acceptable audio-codec lane. AAC remains allowed so weak fallback releases can still download, but it sits behind EAC3, AC3, DDP, and Atmos once those exist.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: AAC Fallback Marker', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: AAC Fallback Marker', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: Stereo-2.0 Fallback', '(?i)\b(?:1[ ._-]?0|2[ ._-]?(?:0|1)|1ch|2ch|1\.0ch|2\.0ch|2\.1ch|stereo|mono|dual[ ._-]?mono)\b', 'Low-tier stereo fallback signal for 2.0, 2.1, stereo, mono, and dual-mono style tags. Additive movie profiles can give it a tiny credit so weak audio still lands below richer surround formats without needing a penalty.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Stereo-2.0 Fallback', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Stereo-2.0 Fallback', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: Lossless Size Penalty', '(?i)\b(?:truehd|true[ ._-]?hd|dts[ ._-]?hd|dts[ ._-]?ma|dts[ ._-]?hd[ ._-]?ma|flac|pcm|lpcm)\b', 'Optional space-awareness detector for TrueHD, DTS-HD MA, FLAC, PCM, and LPCM. The default additive profiles leave it unattached, but stricter profiles can still use it when lossless audio starts inflating files too far above practical EAC3/AC3 releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Lossless Size Penalty', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Lossless Size Penalty', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Audio: Lossless Track Bonus', '(?i)\b(?:truehd|true[ ._-]?hd|dts[ ._-]?hd|dts[ ._-]?ma|dts[ ._-]?hd[ ._-]?ma|flac|pcm|lpcm)\b', 'Positive premium-audio detector for TrueHD, DTS-HD MA, FLAC, PCM, and LPCM. Feature-first profiles use it to reward high-quality encoded releases carrying lossless tracks.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Lossless Track Bonus', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Audio: Lossless Track Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Audio: Block AAC-Only', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\baac\b).*$', 'Optional strict detector for 4K releases that only advertise AAC audio. It is available when you want the 4K lane to require stronger surround-friendly audio such as EAC3, AC3, DDP, or Atmos.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Audio: Block AAC-Only', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Audio: Block AAC-Only', 'Audio');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Audio: Block AAC-Only', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Gate: Block Missing 5.1+ Surround', '(?i)^(?=.*\b(?:2160p|4k)\b)(?!.*\b(?:5[ ._-]?1|6[ ._-]?1|7[ ._-]?1|6ch|7ch|8ch|5\.1ch|6\.1ch|7\.1ch|ddp|dd\+|eac3|e-ac-3|ec3|ac3|ac-3|dts(?:[ ._-]?hd)?(?:[ ._-]?ma)?|truehd|true[ ._-]?hd|atmos)\b).*$', 'Optional strict detector for 4K releases that do not show 5.1/6.1/7.1 or a known surround-capable codec marker.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Gate: Block Missing 5.1+ Surround', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Gate: Block Missing 5.1+ Surround', 'Blocking');
